concept.syntax:
// inclusive range: 1,2,3,4,5
for (i in 1..5) println(i)

// exclusive: 0,1,2,3,4
for (i in 0 until 5) println(i)

// countdown with step
for (i in 10 downTo 1 step 2) print("$i ") // 10 8 6 4 2

// repeat N times
repeat(3) { println("hello") }

// while
var x = 0
while (x < 5) { print(x++); print(" ") }

demo.code:
fun main() {
    for (i in 1..3) {
        println("for: $i")
    }
    repeat(2) {
        println("repeat")
    }
    var x = 0
    while (x < 2) {
        println("while: $x")
        x++
    }
}

